export function maskDob(raw) {
  const d = (raw || '').replace(/\D/g, '').slice(0, 8)
  let out = d.slice(0, 2)
  if (d.length > 2) out += '.' + d.slice(2, 4)
  if (d.length > 4) out += '.' + d.slice(4, 8)
  return out
}  // + vDob: if (verdict === 'invalid') return err('Формат: ДД.ММ.ГГГГ')
